"""Test script for Deformable Attention operator using the new optest framework.

This is the new unified test entry point that replaces check_cuda.py and
check_triton.py.

Note: Deformable Attention is a complex operator that uses MultiScaleDeformableAttention
module. This test provides unified support for both CUDA and Triton backends.
"""

import os
import sys
import argparse
from dataclasses import dataclass

import torch
from optest import (
    TestCase,
    TensorSpec,
    ScalarSpec,
    TestConfig,
    CUDABackend,
    TritonBackend,
    run_test,
    print_result,
)

from torch_.ref import torch_kernel

# Add parent directory to path for imports
TESTCASE_DIR = os.path.dirname(__file__)
sys.path.insert(0, TESTCASE_DIR)


@dataclass
class DeformableParams:
    """Deformable Attention test parameters."""

    batch_size: int = 1  # n
    num_queries: int = 200  # lq
    num_heads: int = 8  # m
    embed_dim: int = 512  # d
    num_levels: int = 4  # l
    num_points: int = 4  # k


# Define test case using new framework
# Note: Deformable Attention has complex input requirements that are
# generated in the get_data.py file. The new framework uses the same
# approach but simplified through the TestCase pattern.
testcase = TestCase(
    tensor_specs=[
        # Complex inputs - actual shapes computed at runtime based on spatial_shapes
        TensorSpec("value", torch.float32, (1, 1, 1, 1), "input"),  # Placeholder
        TensorSpec("value_spatial_shapes", torch.int32, (4, 2), "input"),
        TensorSpec("level_start_index", torch.int32, (4,), "input"),
        TensorSpec(
            "sampling_locations", torch.float32, (1, 1, 1, 1, 1, 2), "input"
        ),  # Placeholder
        TensorSpec(
            "attention_weights", torch.float32, (1, 1, 1, 1, 1), "input"
        ),  # Placeholder
        TensorSpec("output", torch.float32, (1, 1, 1), "output"),  # Placeholder
    ],
    scalar_specs=[],
    torch_kernel=torch_kernel,
)


def parse_args():
    """Parse command line arguments."""
    parser = argparse.ArgumentParser(
        description="Deformable kernel test (new framework)"
    )
    parser.add_argument(
        "--compile-only",
        action="store_true",
        help="Only compile the kernel without running tests",
    )
    parser.add_argument(
        "--no-perf", action="store_true", help="Disable performance testing"
    )
    parser.add_argument(
        "--backend",
        choices=["cuda", "triton"],
        default="cuda",
        help="Backend to test (default: cuda)",
    )
    return parser.parse_args()


def main():
    """Main test entry point."""
    args = parse_args()

    # Create test configuration
    config = TestConfig(
        enable_perf=not args.no_perf,
        compile_only=args.compile_only,
    )

    # Create backend
    if args.backend == "cuda":
        backend = CUDABackend()
    else:  # triton
        backend = TritonBackend()

    # Create test parameters
    params = DeformableParams()

    # Run test
    print(f"\n{'=' * 80}")
    print(f"Testing Deformable Attention operator with {backend.name} backend")
    print(
        f"Batch: {params.batch_size}, Queries: {params.num_queries}, Heads: {params.num_heads}"
    )
    print(
        f"Embed dim: {params.embed_dim}, Levels: {params.num_levels}, Points: {params.num_points}"
    )
    print(f"{'=' * 80}\n")

    result = run_test(
        testcase_dir=TESTCASE_DIR,
        testcase=testcase,
        backend=backend,
        params=params,
        config=config,
    )

    # Print results
    if not args.compile_only:
        print_result(result)

    return 0 if result.passed or result.skipped else 1


if __name__ == "__main__":
    sys.exit(main())

